namespace sv_c78ae9a68c224013a4e041686fcaef18.Models;

public class ApplicationData
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public ExperienceInfo Experience { get; set; } = new();
    public ReferencesInfo References { get; set; } = new();
    public HashSet<int> CompletedSteps { get; set; } = [];
}

public class PersonalInfo
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class ExperienceInfo
{
    public List<JobEntry> Jobs { get; set; } = [];
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferencesInfo
{
    public List<ReferenceContact> Contacts { get; set; } = [];
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

using System.Collections.Concurrent;
using sv_c78ae9a68c224013a4e041686fcaef18.Models;

namespace sv_c78ae9a68c224013a4e041686fcaef18.Services;

/// <summary>
/// Singleton store for wizard data, keyed by session ID.
/// Both the static layout and interactive pages resolve the session ID
/// from HttpContext.Session and use it to access the same data.
/// </summary>
public class ApplicationDataStore
{
    private readonly ConcurrentDictionary<string, ApplicationData> _store = new();

    public ApplicationData GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new ApplicationData());

    public void Remove(string sessionId)
        => _store.TryRemove(sessionId, out _);
}

