@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_c78ae9a68c224013a4e041686fcaef18.Services.ApplicationDataStore Store

@{
    var sessionId = HttpContextAccessor.HttpContext?.Session?.Id ?? "";
    var data = Store.GetOrCreate(sessionId);
    var currentPath = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
    var currentStep = Steps.FindIndex(s => s.Path.Equals(currentPath, StringComparison.OrdinalIgnoreCase)) + 1;
    if (currentStep == 0) currentStep = 1;
}

<div class="container py-4">
    <h3 class="mb-3">Job Application — Step @currentStep of @Steps.Count</h3>

    <div class="progress mb-3" style="height: 8px;">
        <div class="progress-bar" role="progressbar"
             style="width: @(currentStep * 100 / Steps.Count)%">
        </div>
    </div>

    <nav class="nav nav-pills mb-4">
        @for (var i = 0; i < Steps.Count; i++)
        {
            var step = Steps[i];
            var stepNum = i + 1;
            var isActive = stepNum == currentStep;
            var isCompleted = data.CompletedSteps.Contains(stepNum);
            var css = isActive ? "nav-link active" : isCompleted ? "nav-link text-success" : "nav-link";

            <a href="@step.Path" class="@css">
                @if (isCompleted) { <span>✓ </span> }
                @step.Label
            </a>
        }
    </nav>

    <article>
        @Body
    </article>
</div>

@code {
    private record StepInfo(string Path, string Label);

    private static readonly List<StepInfo> Steps =
    [
        new("/apply/personal-info", "Personal Info"),
        new("/apply/experience", "Experience"),
        new("/apply/references", "References"),
        new("/apply/review", "Review"),
    ];
}

@page "/apply/personal-info"
@layout WizardLayout
@rendermode InteractiveServer

@inject IHttpContextAccessor HttpContextAccessor
@inject sv_c78ae9a68c224013a4e041686fcaef18.Services.ApplicationDataStore Store
@inject NavigationManager Nav

<PageTitle>Personal Info</PageTitle>

<h4>Personal Information</h4>

<EditForm Model="Model" OnValidSubmit="HandleNext" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Model.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="Model.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    private string _sessionId = "";
    private PersonalInfo Model { get; set; } = new();

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Session?.Id ?? "";
        var data = Store.GetOrCreate(_sessionId);
        // Copy stored values into the form model
        Model = new PersonalInfo
        {
            Name = data.PersonalInfo.Name,
            Email = data.PersonalInfo.Email,
        };
    }

    private void HandleNext()
    {
        var data = Store.GetOrCreate(_sessionId);
        data.PersonalInfo.Name = Model.Name;
        data.PersonalInfo.Email = Model.Email;
        data.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience", forceLoad: true);
    }
}

@page "/apply/experience"
@layout WizardLayout
@rendermode InteractiveServer

@inject IHttpContextAccessor HttpContextAccessor
@inject sv_c78ae9a68c224013a4e041686fcaef18.Services.ApplicationDataStore Store
@inject NavigationManager Nav

<PageTitle>Experience</PageTitle>

<h4>Work Experience</h4>

@for (var i = 0; i < Jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>Job @(index + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="Jobs[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="Jobs[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="Jobs[index].Years" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary me-2" @onclick="AddJob">+ Add Job</button>
<button type="button" class="btn btn-secondary me-2" @onclick="GoBack">← Back</button>
<button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>

@code {
    private string _sessionId = "";
    private List<JobEntry> Jobs { get; set; } = [];

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Session?.Id ?? "";
        var data = Store.GetOrCreate(_sessionId);
        // Deep copy so edits don't mutate the store until save
        Jobs = data.Experience.Jobs
            .Select(j => new JobEntry { Company = j.Company, Title = j.Title, Years = j.Years })
            .ToList();
        if (Jobs.Count == 0) Jobs.Add(new JobEntry());
    }

    private void AddJob() => Jobs.Add(new JobEntry());
    private void RemoveJob(int index) { if (Jobs.Count > 1) Jobs.RemoveAt(index); }

    private void SaveData()
    {
        var data = Store.GetOrCreate(_sessionId);
        data.Experience.Jobs = Jobs
            .Select(j => new JobEntry { Company = j.Company, Title = j.Title, Years = j.Years })
            .ToList();
        data.CompletedSteps.Add(2);
    }

    private void GoBack()
    {
        SaveData();
        Nav.NavigateTo("/apply/personal-info", forceLoad: true);
    }

    private void HandleNext()
    {
        SaveData();
        Nav.NavigateTo("/apply/references", forceLoad: true);
    }
}

