+@inherits LayoutComponentBase
+@inject NavigationManager Nav
+@inject IHttpContextAccessor HttpContextAccessor
+@inject sv_c78ae9a68c224013a4e041686fcaef18.Services.ApplicationDataStore Store
+
+@{
+    var sessionId = HttpContextAccessor.HttpContext?.Session?.Id ?? "";
+    var data = Store.GetOrCreate(sessionId);
+    var currentPath = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
+    var currentStep = Steps.FindIndex(s => s.Path.Equals(currentPath, StringComparison.OrdinalIgnoreCase)) + 1;
+    if (currentStep == 0) currentStep = 1;
+}
+
+<div class="container py-4">
+    <h3 class="mb-3">Job Application — Step @currentStep of @Steps.Count</h3>
+
+    <div class="progress mb-3" style="height: 8px;">
+        <div class="progress-bar" role="progressbar"
+             style="width: @(currentStep * 100 / Steps.Count)%">
+        </div>
+    </div>
+
+    <nav class="nav nav-pills mb-4">
+        @for (var i = 0; i < Steps.Count; i++)
+        {
+            var step = Steps[i];
+            var stepNum = i + 1;
+            var isActive = stepNum == currentStep;
+            var isCompleted = data.CompletedSteps.Contains(stepNum);
+            var css = isActive ? "nav-link active" : isCompleted ? "nav-link text-success" : "nav-link";
+
+            <a href="@step.Path" class="@css">
+                @if (isCompleted) { <span>✓ </span> }
+                @step.Label
+            </a>
+        }
+    </nav>
+
+    <article>
+        @Body
+    </article>
+</div>
+
+@code {
+    private record StepInfo(string Path, string Label);
+
+    private static readonly List<StepInfo> Steps =
+    [
+        new("/apply/personal-info", "Personal Info"),
+        new("/apply/experience", "Experience"),
+        new("/apply/references", "References"),
+        new("/apply/review", "Review"),
+    ];
+}
+

