</EditForm>

@code {
    private string _sessionId = "";
    private PersonalInfo Model { get; set; } = new();

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Session?.Id ?? "";
        var data = Store.GetOrCreate(_sessionId);
        // Copy stored values into the form model
        Model = new PersonalInfo
        {
            Name = data.PersonalInfo.Name,
            Email = data.PersonalInfo.Email,
        };
    }

    private void HandleNext()
    {
        var data = Store.GetOrCreate(_sessionId);
        data.PersonalInfo.Name = Model.Name;
        data.PersonalInfo.Email = Model.Email;
        data.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience", forceLoad: true);
    }
}

