@page "/apply/experience"
@layout WizardLayout
@rendermode InteractiveServer

@inject IHttpContextAccessor HttpContextAccessor
@inject sv_c78ae9a68c224013a4e041686fcaef18.Services.ApplicationDataStore Store
@inject NavigationManager Nav

<PageTitle>Experience</PageTitle>

<h4>Work Experience</h4>

@for (var i = 0; i < Jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>Job @(index + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="Jobs[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="Jobs[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="Jobs[index].Years" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary me-2" @onclick="AddJob">+ Add Job</button>
<button type="button" class="btn btn-secondary me-2" @onclick="GoBack">← Back</button>
<button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>

@code {
    private string _sessionId = "";
    private List<JobEntry> Jobs { get; set; } = [];

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Session?.Id ?? "";
        var data = Store.GetOrCreate(_sessionId);
        // Deep copy so edits don't mutate the store until save
        Jobs = data.Experience.Jobs
            .Select(j => new JobEntry { Company = j.Company, Title = j.Title, Years = j.Years })
            .ToList();
        if (Jobs.Count == 0) Jobs.Add(new JobEntry());
    }

    private void AddJob() => Jobs.Add(new JobEntry());
    private void RemoveJob(int index) { if (Jobs.Count > 1) Jobs.RemoveAt(index); }

    private void SaveData()
    {
        var data = Store.GetOrCreate(_sessionId);
        data.Experience.Jobs = Jobs
            .Select(j => new JobEntry { Company = j.Company, Title = j.Title, Years = j.Years })
            .ToList();
        data.CompletedSteps.Add(2);
    }

    private void GoBack()
    {
        SaveData();
        Nav.NavigateTo("/apply/personal-info", forceLoad: true);
    }

    private void HandleNext()
    {
        SaveData();
        Nav.NavigateTo("/apply/references", forceLoad: true);
    }
}

