+    var index = i;
+    <div class="card mb-3 p-3">
+        <div class="d-flex justify-content-between">
+            <strong>Reference @(index + 1)</strong>
+            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveContact(index)">Remove</button>
+        </div>
+        <div class="mb-2">
+            <label class="form-label">Name</label>
+            <input class="form-control" @bind="Contacts[index].Name" />
+        </div>
+        <div class="mb-2">
+            <label class="form-label">Email</label>
+            <input class="form-control" @bind="Contacts[index].Email" />
+        </div>
+        <div class="mb-2">
+            <label class="form-label">Relationship</label>
+            <input class="form-control" @bind="Contacts[index].Relationship" />
+        </div>
+    </div>
+}
+
+<button type="button" class="btn btn-outline-secondary me-2" @onclick="AddContact">+ Add Reference</button>
+<button type="button" class="btn btn-secondary me-2" @onclick="GoBack">← Back</button>
+<button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
+
+@code {
+    private string _sessionId = "";
+    private List<ReferenceContact> Contacts { get; set; } = [];
+
+    protected override void OnInitialized()
+    {
+        _sessionId = HttpContextAccessor.HttpContext?.Session?.Id ?? "";
+        var data = Store.GetOrCreate(_sessionId);
+        Contacts = data.References.Contacts
+            .Select(c => new ReferenceContact { Name = c.Name, Email = c.Email, Relationship = c.Relationship })
+            .ToList();
+        if (Contacts.Count == 0) Contacts.Add(new ReferenceContact());
+    }
+
+    private void AddContact() => Contacts.Add(new ReferenceContact());
+    private void RemoveContact(int index) { if (Contacts.Count > 1) Contacts.RemoveAt(index); }
+
+    private void SaveData()
+    {
+        var data = Store.GetOrCreate(_sessionId);
+        data.References.Contacts = Contacts
+            .Select(c => new ReferenceContact { Name = c.Name, Email = c.Email, Relationship = c.Relationship })
+            .ToList();
+        data.CompletedSteps.Add(3);
+    }
+
+    private void GoBack()
+    {
+        SaveData();
+        Nav.NavigateTo("/apply/experience", forceLoad: true);
+    }
+
+    private void HandleNext()
+    {
+        SaveData();
+        Nav.NavigateTo("/apply/review", forceLoad: true);
+    }
+}
+

toolArgs.file_text:
@page "/apply/review"
@layout WizardLayout
@rendermode InteractiveServer

@inject IHttpContextAccessor HttpContextAccessor
@inject sv_c78ae9a68c224013a4e041686fcaef18.Services.ApplicationDataStore Store
@inject NavigationManager Nav

<PageTitle>Review Application</PageTitle>

<h4>Review Your Application</h4>

@if (Data is not null)
{
    <div class="card mb-3 p-3">
        <h5>Personal Information</h5>
        <p><strong>Name:</strong> @Data.PersonalInfo.Name</p>
        <p><strong>Email:</strong> @Data.PersonalInfo.Email</p>
    </div>

    <div class="card mb-3 p-3">
        <h5>Work Experience</h5>
        @if (Data.Experience.Jobs.Count == 0)
        {
            <p class="text-muted">No jobs added.</p>
        }
        else
        {
            @foreach (var job in Data.Experience.Jobs)
            {
                <div class="mb-2">
                    <strong>@job.Title</strong> at @job.Company — @job.Years
                </div>
            }
        }
    </div>

    <div class="card mb-3 p-3">
        <h5>References</h5>
        @if (Data.References.Contacts.Count == 0)
        {
            <p class="text-muted">No references added.</p>
        }
        else
        {
            @foreach (var contact in Data.References.Contacts)
            {
                <div class="mb-2">
                    <strong>@contact.Name</strong> (@contact.Email) — @contact.Relationship
                </div>
            }
        }
    </div>
}

<button type="button" class="btn btn-secondary me-2" @onclick="GoBack">← Back</button>
<button type="button" class="btn btn-success" @onclick="Submit">Submit Application</button>

@if (_submitted)
{
    <div class="alert alert-success mt-3">Your application has been submitted!</div>
}

@code {
    private string _sessionId = "";
    private ApplicationData? Data;
    private bool _submitted;

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Session?.Id ?? "";
        Data = Store.GetOrCreate(_sessionId);
    }

    private void GoBack()
    {
        Nav.NavigateTo("/apply/references", forceLoad: true);
    }

    private void Submit()
    {
        // In a real app you'd persist to a database here
        Data?.CompletedSteps.Add(4);
        _submitted = true;
    }
}

